import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const Upload = () => {
  const [title, setTitle] = useState('');
  const [artist, setArtist] = useState('');
  const [audio, setAudio] = useState(null);
  const [image, setImage] = useState(null);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!audio || !title || !artist) return alert("Please fill required fields");

    const formData = new FormData();
    formData.append('title', title);
    formData.append('artist', artist);
    formData.append('audio', audio);
    if (image) formData.append('image', image);

    setLoading(true);
    try {
      await axios.post('http://localhost:5000/api/songs/upload', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      setLoading(false);
      navigate('/'); // Quay về trang chủ sau khi upload xong
    } catch (err) {
      console.error(err);
      setLoading(false);
      alert("Upload failed!");
    }
  };

  return (
    <div className="max-w-2xl mx-auto p-8 bg-white shadow-md rounded-lg mt-10">
      <h2 className="text-2xl font-bold mb-6">Upload New Track</h2>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-gray-700">Title</label>
          <input type="text" className="w-full border p-2 rounded" value={title} onChange={e => setTitle(e.target.value)} required />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700">Artist</label>
          <input type="text" className="w-full border p-2 rounded" value={artist} onChange={e => setArtist(e.target.value)} required />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700">Audio File (MP3)</label>
          <input type="file" accept="audio/*" className="w-full border p-2 rounded" onChange={e => setAudio(e.target.files[0])} required />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700">Cover Image</label>
          <input type="file" accept="image/*" className="w-full border p-2 rounded" onChange={e => setImage(e.target.files[0])} />
        </div>
        
        <button 
            type="submit" 
            disabled={loading}
            className={`w-full py-2 px-4 rounded text-white font-bold ${loading ? 'bg-gray-400' : 'bg-orange-500 hover:bg-orange-600'}`}
        >
            {loading ? 'Uploading...' : 'Upload Track'}
        </button>
      </form>
    </div>
  );
};

export default Upload;
